type T_AssertionPassResult = {
    lhsExpr: string;
    rhsExpr: string;
    rhsOperand: string;
    operator: string;
    status: string;
};
type T_AssertionFailResult = {
    lhsExpr: string;
    rhsExpr: string;
    rhsOperand: string;
    operator: string;
    status: string;
    error: string;
};
type T_AssertionResult = T_AssertionPassResult | T_AssertionFailResult;
type T_TestPassResult = {
    status: string;
    description: string;
    uid?: string;
    isScriptError?: boolean;
};
type T_TestFailResult = {
    status: string;
    description: string;
    error: string;
    uid?: string;
    isScriptError?: boolean;
};
type T_TestResult = T_TestPassResult | T_TestFailResult;
type T_EmptyRequest = {
    method?: null | undefined;
    url?: null | undefined;
    headers?: null | undefined;
    data?: null | undefined;
    isHtml?: boolean | undefined;
};
type T_Request = {
    method: string;
    url: string;
    headers: Record<string, string | number | undefined>;
    data: string | object | null | boolean | number;
    isHtml?: boolean;
};
type T_EmptyResponse = {
    status?: null | undefined;
    statusText?: null | undefined;
    headers?: null | undefined;
    data?: null | undefined;
    responseTime?: number | undefined;
    isHtml?: boolean | undefined;
};
type T_SkippedResponse = {
    status?: string | null | undefined;
    statusText?: string | null | undefined;
    headers?: null | undefined;
    data?: null | undefined;
    responseTime?: number | undefined;
    isHtml?: boolean | undefined;
};
type T_Response = {
    status: number | string;
    statusText: string;
    headers: Record<string, string | number | undefined>;
    data: string | object | null | boolean | number;
    isHtml?: boolean;
};
type T_RunnerRequestExecutionResult = {
    iterationIndex: number;
    name: string;
    path: string;
    request: T_EmptyRequest | T_Request;
    response: T_EmptyResponse | T_Response | T_SkippedResponse;
    status: null | undefined | string;
    skipped?: boolean;
    skipReason?: string;
    error: null | undefined | string;
    assertionResults?: T_AssertionResult[];
    testResults?: T_TestResult[];
    preRequestTestResults?: T_TestResult[];
    postResponseTestResults?: T_TestResult[];
    runDuration: number;
};
type T_RunnerResults = {
    iterationIndex: number;
    iterationData?: any;
    results: T_RunnerRequestExecutionResult[];
    summary: T_RunSummary;
};
type T_RunSummary = {
    totalRequests: number;
    passedRequests: number;
    failedRequests: number;
    errorRequests: number;
    skippedRequests: number;
    skippedByBail: number;
    totalAssertions: number;
    passedAssertions: number;
    failedAssertions: number;
    totalTests: number;
    passedTests: number;
    failedTests: number;
    totalPreRequestTests: number;
    passedPreRequestTests: number;
    failedPreRequestTests: number;
    totalPostResponseTests: number;
    passedPostResponseTests: number;
    failedPostResponseTests: number;
};

declare const generateHtmlReport: ({ runnerResults, version, environment, runCompletionTime, secretValues }: {
    runnerResults: T_RunnerResults[];
    version?: string | undefined;
    environment?: string | null | undefined;
    runCompletionTime?: string | undefined;
    secretValues?: string[] | undefined;
}) => string;

declare const getRunnerSummary: (results: T_RunnerRequestExecutionResult[]) => T_RunSummary;

/**
 * Main masking function that applies comprehensive masking to any JSON structure.
 * This is the public API that pre-compiles regex patterns for better performance.
 *
 * This function recursively traverses JSON data and applies masking based on:
 * 1. Header names (sensitive headers are always masked)
 * 2. Content patterns (Authorization schemes are preserved)
 * 3. Secret values (regex-based replacement)
 *
 * @example
 * Input: { headers: { 'Authorization': 'Bearer secret123' }, url: 'https://api.com?token=secret456' }
 * Output: { headers: { 'Authorization': 'Bearer ********' }, url: 'https://api.com?token=********' }
 */
declare const walkAndMask: (node: any, options?: {
    secretValues?: string[];
}) => any;

export { generateHtmlReport, getRunnerSummary, walkAndMask };
